class PaymentProcessor {
  process(method: string, amount: number): Receipt {
    if (method === 'credit_card') {
      return this.stripe.charge(amount);
    } else if (method === 'paypal') {
      return this.paypal.send(amount);
    } else if (method === 'bank_transfer') {
      return this.bank.transfer(amount);
    }
    throw new Error('Unsupported method');
  }
}

class ReportFormatter {
  format(report: Report, outputType: string): string {
    if (outputType === 'html') {
      return `<h1>${report.title}</h1><p>${report.body}</p>`;
    } else if (outputType === 'markdown') {
      return `# ${report.title}\n\n${report.body}`;
    } else if (outputType === 'plain') {
      return `${report.title}\n${report.body}`;
    }
    return '';
  }
}

// Version A
interface Notifier { send(message: string): void; }
class NotificationService {
  constructor(private notifiers: Notifier[]) {}
  broadcast(message: string): void {
    this.notifiers.forEach(n => n.send(message));
  }
}
// Version B
class NotificationService {
  send(type: string, message: string): void {
    if (type === 'slack')   this.slack.post(message);
    if (type === 'webhook') this.http.post(this.webhookUrl, message);
  }
}
